#!/usr/bin/env node
'use strict';

const fs = require('fs');
const path = require('path');

const ts = require('typescript');

const repoRoot = path.resolve(__dirname, '..');
const useBuildOutput = process.argv.includes('--build-output');
const runtimeRoot = useBuildOutput
  ? path.join(repoRoot, '.build')
  : repoRoot;
const outputFile = path.join(runtimeRoot, 'electron', 'preload', 'canva.bundle.js');

const entryModule = 'electron/preload/canva.js';
const moduleIds = [
  'electron/shared/debug.js',
  'electron/preload/debug.js',
  'electron/preload/upload-diagnostics.js',
  'electron/preload/browser-capture-diagnostics.js',
  'electron/preload/eyedropper-routing-diagnostics.js',
  'electron/preload/ltcode-eyedropper.js',
  'electron/preload/custom-eyedropper-flow.js',
  'electron/preload/native-eyedropper-wrapper.js',
  'electron/preload/canva.js',
];

function sourceCandidates(id) {
  if (useBuildOutput || !id.endsWith('.js')) {
    return [id];
  }

  return [id, id.replace(/\.js$/, '.ts')];
}

function resolveSourceModule(id) {
  for (const candidate of sourceCandidates(id)) {
    const file = path.join(runtimeRoot, candidate);
    if (fs.existsSync(file)) {
      return { id: candidate, file };
    }
  }

  return {
    id,
    file: path.join(runtimeRoot, id),
  };
}

function readModuleSource(id) {
  const sourceModule = resolveSourceModule(id);
  const source = fs.readFileSync(sourceModule.file, 'utf8');

  if (!sourceModule.id.endsWith('.ts')) {
    return source;
  }

  return ts.transpileModule(source, {
    compilerOptions: {
      module: ts.ModuleKind.CommonJS,
      target: ts.ScriptTarget.ES2022,
      esModuleInterop: true,
      sourceMap: false,
    },
    fileName: sourceModule.file,
  }).outputText;
}

function indentSource(source) {
  return source
    .split('\n')
    .map((line) => `      ${line}`)
    .join('\n');
}

function moduleWrapper(id) {
  const source = readModuleSource(id);

  return [
    `  ${JSON.stringify(id)}: function moduleFactory(module, exports, require) {`,
    indentSource(source),
    '  }',
  ].join('\n');
}

const bundle = [
  '// Generated by scripts/build-preload-bundle.js.',
  '// Do not edit this file directly. Edit electron/preload source modules instead.',
  "'use strict';",
  '',
  '(function canvaPreloadBundle(nativeRequire) {',
  '  const moduleDefinitions = {',
  moduleIds.map(moduleWrapper).join(',\n'),
  '  };',
  '',
  '  const moduleCache = Object.create(null);',
  '',
  '  function normalizeModuleId(value) {',
  "    const parts = String(value).split('/');",
  '    const normalized = [];',
  '',
  '    for (const part of parts) {',
  "      if (!part || part === '.') continue;",
  "      if (part === '..') {",
  '        normalized.pop();',
  '        continue;',
  '      }',
  '      normalized.push(part);',
  '    }',
  '',
  "    return normalized.join('/');",
  '  }',
  '',
  '  function moduleDir(moduleId) {',
  "    const parts = String(moduleId).split('/');",
  '    parts.pop();',
  "    return parts.join('/');",
  '  }',
  '',
  '  function resolveModuleId(fromModuleId, request) {',
  '    const raw = String(request);',
  '',
  "    if (raw.startsWith('./') || raw.startsWith('../')) {",
  "      let resolved = normalizeModuleId(moduleDir(fromModuleId) + '/' + raw);",
  "      if (!resolved.endsWith('.js')) {",
  "        resolved += '.js';",
  '      }',
  '      return resolved;',
  '    }',
  '',
  '    return raw;',
  '  }',
  '',
  '  function loadModule(moduleId) {',
  '    if (moduleCache[moduleId]) {',
  '      return moduleCache[moduleId].exports;',
  '    }',
  '',
  '    const factory = moduleDefinitions[moduleId];',
  '    if (!factory) {',
  '      return nativeRequire(moduleId);',
  '    }',
  '',
  '    const module = { exports: {} };',
  '    moduleCache[moduleId] = module;',
  '',
  '    factory(module, module.exports, function bundledRequire(request) {',
  '      const resolved = resolveModuleId(moduleId, request);',
  '',
  '      if (moduleDefinitions[resolved]) {',
  '        return loadModule(resolved);',
  '      }',
  '',
  '      return nativeRequire(request);',
  '    });',
  '',
  '    return module.exports;',
  '  }',
  '',
  `  loadModule(${JSON.stringify(entryModule)});`,
  '})(require);',
  '',
].join('\n');

fs.writeFileSync(outputFile, bundle);
console.log(`[preload-bundle] wrote ${path.relative(repoRoot, outputFile)}`);
